		shipmentID := total_ship + jj
		bestTrial := trialRecord{costDelta: 1e18, success: false}
		probedLimit := dispatch.AssignsLen
		if probedLimit == 0 {
			probedLimit = 1
		}
		for aa := 0; aa <= probedLimit; aa++ {
			actualIdx := aa
			if aa == probedLimit && aa < MAXASSIGNS {
				actualIdx = dispatch.AssignsLen
				if actualIdx >= MAXASSIGNS {
					continue
				}
			}
			tr := &trialRecord{assignIdx: actualIdx}
