				tr.beforeCost = dispatch.Assigns[actualIdx].Cost
				tr.stationSave = dispatch.Assigns[actualIdx].StationCurrent
				tr.saveLen = dispatch.Assigns[actualIdx].StationsLen
				tr.snapshotOK = true
