				if ok {
					dispatch.Assigns[tryIdx].GenRoute()
					if tryIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = tryIdx + 1
					}
					inserted = true
					fallbackSeed = (fallbackSeed + 1) % MAXASSIGNS
					break
				}
				dispatch.Assigns[tryIdx].RemoveShip(shipmentID)
				dispatch.Assigns[tryIdx].GenRoute()
			}
