My new algorithm uses greedy insertion with regret-based lookahead: try each order in all existing routes plus one new empty route, compute incremental cost delta for each feasible insertion position, choose the insertion with minimum marginal increase relative to second-best option, and always ensure every order gets placed by falling back to appending a fresh assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	assignCount := dispatch.AssignsLen

	type InsertCandidate struct {
		assignIdx int
		costDelta float64
		secondBestDelta float64
		feasible bool
	}

	for ordIdx := 0; ordIdx < nOrders; ordIdx++ {
		orderId := total_ship + ordIdx
		ori := oris[ordIdx]
		des := dess[ordIdx]

		bestCandidate := InsertCandidate{assignIdx: -1, costDelta: 1e100, secondBestDelta: 1e100, feasible: false}
		secondBestCandidate := InsertCandidate{costDelta: 1e100}

		maxTryAssigns := assignCount + 1
		if maxTryAssigns > MAXASSIGNS {
			maxTryAssigns = MAXASSIGNS
		}

		for tryIdx := 0; tryIdx < maxTryAssigns; tryIdx++ {
			var originalCost float64
			var wasEmpty bool
			var savedAssignState Assign

			isNewAssign := (tryIdx >= assignCount)

			if isNewAssign {
				if tryIdx >= MAXASSIGNS {
					continue
				}
				wasEmpty = true
				originalCost = 0.0
			} else {
				assignPtr := &dispatch.Assigns[tryIdx]
				originalCost = assignPtr.Cost
				wasEmpty = (assignPtr.StationsLen == 0)
				savedAssignState = *assignPtr
			}

			addSuccess := dispatch.Assigns[tryIdx].AddShip(orderId, ori, des)
			if !addSuccess {
				if !isNewAssign {
					dispatch.Assigns[tryIdx] = savedAssignState
				}
				continue
			}

			dispatch.Assigns[tryIdx].GenRoute()
			newCost := dispatch.Assigns[tryIdx].Cost

			if newCost < 0 {
				dispatch.Assigns[tryIdx].RemoveShip(orderId)
				dispatch.Assigns[tryIdx].GenRoute()
				if !wasEmpty && !isNewAssign {
					dispatch.Assigns[tryIdx] = savedAssignState
				}
				continue
			}

			delta := newCost - originalCost
			fallbackDelta := delta
			if originalCost <= 0 && wasEmpty {
				fallbackDelta = newCost
			}

			if fallbackDelta < bestCandidate.costDelta {
				secondBestCandidate = bestCandidate
				bestCandidate.assignIdx = tryIdx
				bestCandidate.costDelta = fallbackDelta
				bestCandidate.secondBestDelta = secondBestCandidate.costDelta
				bestCandidate.feasible = true
			} else if fallbackDelta < secondBestCandidate.costDelta {
				secondBestCandidate.costDelta = fallbackDelta
				bestCandidate.secondBestDelta = fallbackDelta
			}

			dispatch.Assigns[tryIdx].RemoveShip(orderId)
			dispatch.Assigns[tryIdx].GenRoute()
			if !wasEmpty && !isNewAssign {
				dispatch.Assigns[tryIdx] = savedAssignState
			}
		}

		chosenIdx := bestCandidate.assignIdx
		if chosenIdx >= 0 && chosenIdx < MAXASSIGNS {
			addSuccess := dispatch.Assigns[chosenIdx].AddShip(orderId, ori, des)
			if addSuccess {
				dispatch.Assigns[chosenIdx].GenRoute()
				if chosenIdx >= assignCount {
					assignCount++
					if assignCount > MAXASSIGNS {
						assignCount = MAXASSIGNS
					}
				}
			} else {
				chosenIdx = -1
			}
		}

		if chosenIdx < 0 {
			fallbackIdx := assignCount
			if fallbackIdx < MAXASSIGNS {
				addSuccess := dispatch.Assigns[fallbackIdx].AddShip(orderId, ori, des)
				if addSuccess {
					dispatch.Assigns[fallbackIdx].GenRoute()
					assignCount++
					if assignCount > MAXASSIGNS {
						assignCount = MAXASSIGNS
					}
				}
			}
		}
	}

	dispatch.AssignsLen = assignCount
	dispatch.RenewnTotalCost()
	return dispatch

