func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		feasible   bool
	}

	// Process each ship order sequentially
	for shipIDOffset := range oris {
		ori := oris[shipIDOffset]
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset

		bestCandidate := candidate{-1, 0.0, false}

		// Try inserting into existing non-empty assigns first (shuffled)
		existingIndices := make([]int, 0, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen > 0 {
				existingIndices = append(existingIndices, i)
			}
		}
		// Shuffle to avoid bias
		for i := len(existingIndices) - 1; i > 0; i-- {
			j := i % (i + 1)
			existingIndices[i], existingIndices[j] = existingIndices[j], existingIndices[i]
		}

		for _, idx := range existingIndices {
			origCost := dispatch.Assigns[idx].Cost
			success := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					delta := newCost - origCost
					if !bestCandidate.feasible || delta < bestCandidate.costDelta {
						bestCandidate = candidate{idx, delta, true}
					}
				}
				// Undo trial insertion
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].GenRoute()
			}
		}

		// Also try empty/new assigns (including potential new ones within MAXASSIGNS)
		maxTryAssigns := dispatch.AssignsLen + 10
		if maxTryAssigns > MAXASSIGNS {
			maxTryAssigns = MAXASSIGNS
		}
		for idx := dispatch.AssignsLen; idx < maxTryAssigns; idx++ {
			// Ensure we don't exceed bounds
			if idx >= MAXASSIGNS {
				break
			}
			origCost := dispatch.Assigns[idx].Cost
			success := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[idx].GenRoute()
				newCost := dispatch.Assigns[idx].Cost
				if newCost >= 0 {
					delta := newCost - origCost
					if !bestCandidate.feasible || delta < bestCandidate.costDelta {
						bestCandidate = candidate{idx, delta, true}
					}
				}
				// Undo trial insertion
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].GenRoute()
			}
		}

		// Commit best feasible insertion
		if bestCandidate.feasible {
			idx := bestCandidate.assignIdx
			dispatch.Assigns[idx].AddShip(shipID, ori, des)
			dispatch.Assigns[idx].GenRoute()
			// Expand AssignsLen if we used a new assign slot
			if idx >= dispatch.AssignsLen {
				dispatch.AssignsLen = idx + 1
			}
		} else {
			// Fallback: create a new assign if needed and force insertion
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx >= MAXASSIGNS {
